from answer import answer_question, format_answer_outputdef run_query(query: str):    """    Wrapper used by CLI and web UI.    """    return answer_question(query)WELCOME_MESSAGE = """I-MED Procedure Q&AAsk a question about a scraped imaging procedure page.Type 'exit' or 'quit' to leave.""".strip()def main() -> None:    print(WELCOME_MESSAGE)    while True:        query = input("\nQuestion: ").strip()        if query.lower() in {"exit", "quit"}:            print("Goodbye.")            break        if not query:            print("Please enter a question.")            continue        try:            response = answer_question(query)            print()            print(format_answer_output(response))        except Exception as e:            print(f"Sorry, something went wrong while answering your question: {e}")if __name__ == "__main__":    main()